sql:
SELECT user_name 
FROM users 
WHERE user_id IN (
  SELECT user_id 
  FROM user_resource_access
);

SELECT DISTINCT t.tech_name
FROM technologies t
INNER JOIN resource_technologies rt ON t.tech_id = rt.tech_id;

SELECT COUNT(*)
FROM resources
WHERE resource_id NOT IN (SELECT resource_id FROM resource_technologies);

SELECT name, NTILE(4) OVER (ORDER BY created_at DESC) AS quartile
FROM resources
WHERE license = 'MIT' AND purpose = 'educational';

SELECT tag_name, COUNT(*) AS resource_count
FROM resource_tags
GROUP BY tag_name;

SELECT AVG(tag_count) AS average_tags_per_resource
FROM (
    SELECT resource_id, COUNT(tag_name) AS tag_count
    FROM resource_tags
    GROUP BY resource_id
) AS tag_counts_per_resource;

SELECT resource_id, name
FROM resources
ORDER BY updated_at DESC;
